import{_ as t,o as s,c as o,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"Mentions Légales","description":"","frontmatter":{"title":"Mentions Légales"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/legal.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/legal.md"}'),l={name:"docs/fr/advertisers/sponsored-mail/design-guide/legal.md"};function i(n,e,r,d,g,u){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="mentions-legales-logos" tabindex="-1">Mentions Légales &amp; Logos <a class="header-anchor" href="#mentions-legales-logos" aria-label="Permalink to &quot;Mentions Légales &amp; Logos&quot;">​</a></h1><p>Toute publicité imprimée engage votre responsabilité. Ces éléments sont obligatoires sur chaque flyer — leur absence bloque la validation du BAT.</p><hr><h2 id="mentions-universelles" tabindex="-1">Mentions Universelles <a class="header-anchor" href="#mentions-universelles" aria-label="Permalink to &quot;Mentions Universelles&quot;">​</a></h2><p>Ces 3 blocs s&#39;appliquent à <strong>tous les annonceurs</strong>, quel que soit le secteur.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Identification de l&#39;annonceur</strong><p>Nom social · Forme juridique · Capital social · Adresse du siège · Numéro RCS + ville d&#39;immatriculation</p><p><em>Exemple : &quot;ACME SAS au capital de 10 000€ — 12 rue de la Paix, 75001 Paris — RCS Paris 123 456 789&quot;</em></p></div><div class="gi-value-card"><strong>2. Logos Environnement</strong><p><strong>Cartouche Info-tri (Triman)</strong> — taille minimum 8 mm. Obligatoire depuis la Loi AGEC.</p><p><strong>Logo getinside</strong> — fourni avec les gabarits.</p><p><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank">⬇️ Télécharger le pack Logos</a></p></div><div class="gi-value-card"><strong>3. CGV de l&#39;offre</strong><p>Dates de validité de l&#39;offre · Conditions particulières (ex : &quot;valable dès 50€ d&#39;achat&quot;) · Toute restriction d&#39;usage</p></div></div><hr><h2 id="mentions-sectorielles" tabindex="-1">Mentions Sectorielles <a class="header-anchor" href="#mentions-sectorielles" aria-label="Permalink to &quot;Mentions Sectorielles&quot;">​</a></h2><p>Si votre activité relève d&#39;un des secteurs ci-dessous, la mention correspondante est <strong>obligatoire</strong> sur votre flyer.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Secteur</th><th style="text-align:left;">Mention obligatoire</th><th style="text-align:left;">Référence légale</th></tr></thead><tbody><tr><td style="text-align:left;">🍷 <strong>Alcool</strong></td><td style="text-align:left;"><em>&quot;L&#39;abus d&#39;alcool est dangereux pour la santé, à consommer avec modération.&quot;</em> + Interdiction de ciblage des mineurs</td><td style="text-align:left;">Loi Evin — Art. L3323-4</td></tr><tr><td style="text-align:left;">🥗 <strong>Alimentation</strong></td><td style="text-align:left;"><em>&quot;Pour votre santé, mangez au moins cinq fruits et légumes par jour.&quot;</em></td><td style="text-align:left;">Art. L2133-1 CSP — mangerbouger.fr</td></tr><tr><td style="text-align:left;">🚗 <strong>Automobile</strong></td><td style="text-align:left;">Classe énergétique (l/100km et g CO2/km) + <em>&quot;Pensez à covoiturer.&quot;</em></td><td style="text-align:left;">Arrêté du 10 janvier 2018</td></tr><tr><td style="text-align:left;">💰 <strong>Crédit / Finance</strong></td><td style="text-align:left;"><em>&quot;Un crédit vous engage et doit être remboursé. Vérifiez vos capacités de remboursement avant de vous engager.&quot;</em></td><td style="text-align:left;">Art. L311-5 Code de la Consommation</td></tr><tr><td style="text-align:left;">🎰 <strong>Jeux d&#39;argent</strong></td><td style="text-align:left;"><em>&quot;Jouer comporte des risques : endettement, isolement, dépendance. Appelez le 09-74-75-13-13 (appel non surtaxé).&quot;</em> + Interdiction de ciblage des mineurs</td><td style="text-align:left;">ANJ — Loi du 12 mai 2010</td></tr><tr><td style="text-align:left;">💊 <strong>Médicaments / Parapharmacie</strong></td><td style="text-align:left;"><em>&quot;Lire attentivement la notice. Demandez conseil à votre médecin ou pharmacien.&quot;</em></td><td style="text-align:left;">Code de la Santé Publique</td></tr><tr><td style="text-align:left;">🧸 <strong>Jouets</strong></td><td style="text-align:left;">Indication de l&#39;âge recommandé (ex : <em>&quot;3+&quot;</em>) + <em>&quot;Ne convient pas aux enfants de moins de 3 ans.&quot;</em></td><td style="text-align:left;">Directive 2009/48/CE</td></tr><tr><td style="text-align:left;">🛡️ <strong>Assurance</strong></td><td style="text-align:left;"><em>&quot;Un contrat d&#39;assurance vous engage et doit être respecté. Vérifiez les termes avant de vous engager.&quot;</em></td><td style="text-align:left;">Code des Assurances</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">En cas de doute</p><p>Si votre secteur n&#39;est pas listé ou si vous hésitez sur la formulation exacte, transmettez votre BAT à <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a> avant impression — notre équipe valide la conformité légale.</p></div>',11)])])}const p=t(l,[["render",i]]);export{c as __pageData,p as default};
